1	/* ============================================================
2	   Hero — pinned, scroll-scrubbed cinematic. The 3D screen-reveal
3	   pop-out is baked into the video itself (last ~2s = camera pulls
4	   back to reveal the cinema monitor), so the website's only job is
5	   to scrub the canvas and fade brand copy on top.
6	
7	   Layer stack (back → front):
8	     .hero
9	     ├── canvas (fills section, painted by FrameCanvas)
10	     ├── .copyLayer  (brand mark / headline / tagline / CTA)
11	     ├── .scrollHint
12	     └── .loader     (front-most until frames preload)
13	   ============================================================ */
14	
15	.hero {
16	  position: relative;
17	  width: 100%;
18	  height: 100vh;
19	  overflow: hidden;
20	  background: var(--ink);
21	  isolation: isolate;
22	  font-family: var(--font-display);
23	}
24	
25	.canvas {
26	  position: absolute;
27	  inset: 0;
28	  width: 100%;
29	  height: 100%;
30	  display: block;
31	  z-index: 1;
32	}
33	
34	/* ---------- Copy layer ---------- */
35	.copyLayer {
36	  position: absolute;
37	  inset: 0;
38	  z-index: 4;
39	  display: grid;
40	  grid-template-rows: 1fr auto 1fr;
41	  align-items: stretch;
42	  justify-items: center;
43	  padding: clamp(24px, 5vw, 64px);
44	  pointer-events: none;
45	}
46	
47	.copyLayer > * {
48	  pointer-events: auto;
49	}
50	
51	.heroCopy {
52	  grid-row: 1 / 2;
53	  align-self: end;
54	  text-align: center;
55	  color: var(--paper);
56	  text-shadow: 0 2px 24px rgba(0, 0, 0, 0.5);
57	  margin-bottom: clamp(24px, 4vh, 48px);
58	  opacity: 0;
59	}
60	
61	.brandMark {
62	  display: inline-block;
63	  font-family: var(--font-display);
64	  font-weight: 500;
65	  font-size: clamp(11px, 1vw, 13px);
66	  letter-spacing: 0.42em;
67	  text-indent: 0.42em;
68	  color: rgba(255, 255, 255, 0.82);
69	  margin-bottom: clamp(16px, 2vh, 24px);
70	}
71	
72	.headline {
73	  font-family: var(--font-display);
74	  font-weight: 600;
75	  font-size: clamp(48px, 9vw, 132px);
76	  line-height: 0.92;
77	  letter-spacing: -0.04em;
78	  color: var(--paper);
79	}
80	
81	.tagline {
82	  grid-row: 2 / 3;
83	  align-self: center;
84	  font-family: var(--font-display);
85	  font-weight: 400;
86	  font-size: clamp(18px, 1.6vw, 22px);
87	  letter-spacing: 0.01em;
88	  color: var(--paper);
89	  text-align: center;
90	  text-shadow: 0 2px 24px rgba(0, 0, 0, 0.5);
91	  opacity: 0;
92	}
93	
94	.cta {
95	  grid-row: 3 / 4;
96	  align-self: end;
97	  display: inline-flex;
98	  align-items: center;
99	  gap: 12px;
100	  padding: 14px 26px;
101	  border-radius: 999px;
102	  background: var(--paper);
103	  color: var(--ink);
104	  font-family: var(--font-display);
105	  font-weight: 500;
106	  font-size: 15px;
107	  letter-spacing: 0.02em;
108	  opacity: 0;
109	  transition: background 0.35s var(--ease-out-cubic), color 0.35s var(--ease-out-cubic), transform 0.35s var(--ease-out-cubic);
110	  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.35);
111	}
112	
113	.cta:hover {
114	  background: var(--amber);
115	  color: var(--ink);
116	  transform: translateY(-2px);
117	}
118	
119	.cta svg {
120	  transition: transform 0.35s var(--ease-out-cubic);
121	}
122	
123	.cta:hover svg {
124	  transform: translateX(4px);
125	}
126	
127	/* ---------- Scroll hint ---------- */
128	.scrollHint {
129	  position: absolute;
130	  bottom: clamp(20px, 4vh, 40px);
131	  left: 50%;
132	  transform: translateX(-50%);
133	  z-index: 4;
134	  display: flex;
135	  flex-direction: column;
136	  align-items: center;
137	  gap: 12px;
138	  color: rgba(255, 255, 255, 0.7);
139	  font-family: var(--font-display);
140	  font-weight: 500;
141	  font-size: 11px;
142	  letter-spacing: 0.4em;
143	  text-indent: 0.4em;
144	}
145	
146	.scrollHintLine {
147	  width: 1px;
148	  height: 36px;
149	  background: linear-gradient(to bottom, rgba(255, 255, 255, 0.6), rgba(255, 255, 255, 0));
150	  position: relative;
151	  overflow: hidden;
152	}
153	
154	.scrollHintLine::after {
155	  content: '';
156	  position: absolute;
157	  inset: 0;
158	  background: linear-gradient(to bottom, rgba(255, 255, 255, 0.95), rgba(255, 255, 255, 0));
159	  animation: scrollPulse 1.8s ease-in-out infinite;
160	}
161	
162	@keyframes scrollPulse {
163	  0%   { transform: translateY(-100%); }
164	  100% { transform: translateY(100%);  }
165	}
166	
167	/* ---------- Loader ---------- */
168	.loader {
169	  position: absolute;
170	  inset: 0;
171	  z-index: 10;
172	  background: var(--ink);
173	  display: grid;
174	  place-items: center;
175	  transition: opacity 0.6s var(--ease-out-cubic), visibility 0s linear 0.6s;
176	}
177	
178	.loader[data-ready='true'] {
179	  opacity: 0;
180	  visibility: hidden;
181	  pointer-events: none;
182	}
183	
184	.loaderInner {
185	  display: grid;
186	  grid-template-columns: 1fr auto 1fr;
187	  align-items: center;
188	  gap: 24px;
189	  width: min(560px, 70vw);
190	  color: var(--paper);
191	}
192	
193	.loaderMark {
194	  font-family: var(--font-display);
195	  font-weight: 600;
196	  letter-spacing: 0.4em;
197	  font-size: 14px;
198	  justify-self: start;
199	}
200	
201	.loaderCount {
202	  font-family: var(--font-display);
203	  font-weight: 500;
204	  font-size: 14px;
205	  font-variant-numeric: tabular-nums;
206	  letter-spacing: 0.06em;
207	  color: rgba(255, 255, 255, 0.65);
208	}
209	
210	.loaderBar {
211	  grid-column: 1 / -1;
212	  width: 100%;
213	  height: 1px;
214	  background: rgba(255, 255, 255, 0.12);
215	  overflow: hidden;
216	}
217	
218	.loaderBarFill {
219	  width: 100%;
220	  height: 100%;
221	  background: var(--paper);
222	  transform-origin: left;
223	  transform: scaleX(0);
224	  transition: transform 0.25s var(--ease-out-cubic);
225	}
226	
227	/* ---------- Epilogue copy (frozen-frame text reveals) ---------- */
228	.epilogueCopy {
229	  position: absolute;
230	  inset: 0;
231	  z-index: 5;
232	  display: flex;
233	  flex-direction: column;
234	  justify-content: center;
235	  align-items: center;
236	  gap: clamp(12px, 2.5vh, 28px);
237	  pointer-events: none;
238	  padding: clamp(24px, 5vw, 64px);
239	}
240	
241	.epilogueLine {
242	  font-family: var(--font-display);
243	  font-weight: 600;
244	  font-size: clamp(24px, 4vw, 60px);
245	  letter-spacing: 0.08em;
246	  text-indent: 0.08em;
247	  color: var(--paper);
248	  text-shadow: 0 2px 32px rgba(0, 0, 0, 0.45);
249	  opacity: 0;
250	  will-change: transform, opacity;
251	}
252	
253	/* ---------- Bottom gradient — bleeds canvas into next section ---------- */
254	.bottomGradient {
255	  position: absolute;
256	  bottom: 0;
257	  left: 0;
258	  right: 0;
259	  height: 70vh;
260	  z-index: 3;
261	  background: linear-gradient(to bottom, transparent 0%, var(--paper) 100%);
262	  pointer-events: none;
263	  opacity: 0;
264	  will-change: opacity;
265	}
266	
267	@media (prefers-reduced-motion: reduce) {
268	  .scrollHintLine::after {
269	    animation: none;
270	  }
271	}
272	
273	@media (max-width: 720px) {
274	  .copyLayer { padding: 24px 16px; }
275	}
276

1	/* ============================================================
2	   About Section — dark ink, cinematic animations
3	   Transitions: paper (hero) → paper→ink strip → solid ink
4	   ============================================================ */
5	
6	.about {
7	  position: relative;
8	  background: var(--ink);
9	  color: var(--paper);
10	  font-family: var(--font-display);
11	  overflow: hidden;
12	}
13	
14	/* paper→ink transition at the very top */
15	.topFade {
16	  height: 32vh;
17	  background: linear-gradient(to bottom, var(--paper) 0%, var(--ink) 100%);
18	  pointer-events: none;
19	}
20	
21	.inner {
22	  max-width: 1440px;
23	  margin: 0 auto;
24	  padding: clamp(40px, 6vw, 80px) clamp(24px, 6vw, 80px);
25	}
26	
27	/* ---------- Eyebrow ---------- */
28	.eyebrow {
29	  font-size: clamp(10px, 0.8vw, 12px);
30	  font-weight: 500;
31	  letter-spacing: 0.42em;
32	  text-indent: 0.42em;
33	  color: rgba(255, 255, 255, 0.35);
34	  margin-bottom: clamp(20px, 3vh, 32px);
35	  opacity: 0;
36	}
37	
38	/* ---------- Headline — scroll-scrubbed opacity reveal ---------- */
39	.headline {
40	  font-size: clamp(64px, 11vw, 160px);
41	  font-weight: 600;
42	  line-height: 0.95;
43	  letter-spacing: -0.04em;
44	  color: var(--paper);
45	  margin-bottom: clamp(40px, 6vh, 64px);
46	  display: flex;
47	  flex-direction: column;
48	  gap: 0.04em;
49	}
50	
51	.headline em {
52	  font-style: italic;
53	  font-weight: 300;
54	  color: rgba(255, 255, 255, 0.55);
55	}
56	
57	/* each line is individually targeted by GSAP scrub */
58	.hLine {
59	  display: block;
60	  opacity: 0;
61	  transform: translateY(32px);
62	  will-change: opacity, transform;
63	}
64	
65	/* ---------- Body — word wave ---------- */
66	.body {
67	  font-size: clamp(15px, 1.2vw, 18px);
68	  font-weight: 400;
69	  line-height: 1.72;
70	  color: rgba(255, 255, 255, 0.45);
71	  max-width: 560px;
72	  margin-bottom: clamp(48px, 7vh, 80px);
73	}
74	
75	.word {
76	  display: inline;
77	  opacity: 0;
78	}
79	
80	/* ---------- Stats row ---------- */
81	.stats {
82	  display: grid;
83	  grid-template-columns: repeat(3, 1fr);
84	  gap: 0;
85	  border-top: 1px solid rgba(255, 255, 255, 0.08);
86	  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
87	  margin-bottom: 0;
88	}
89	
90	.statItem {
91	  display: flex;
92	  flex-direction: column;
93	  gap: 6px;
94	  padding: clamp(24px, 4vh, 40px) 0;
95	  border-right: 1px solid rgba(255, 255, 255, 0.08);
96	}
97	
98	.statItem:last-child {
99	  border-right: none;
100	}
101	
102	.statValue {
103	  font-size: clamp(40px, 5vw, 72px);
104	  font-weight: 600;
105	  letter-spacing: -0.04em;
106	  color: var(--paper);
107	  font-variant-numeric: tabular-nums;
108	  line-height: 1;
109	}
110	
111	.statLabel {
112	  font-size: clamp(9px, 0.7vw, 11px);
113	  font-weight: 500;
114	  letter-spacing: 0.3em;
115	  text-indent: 0.3em;
116	  color: rgba(255, 255, 255, 0.3);
117	  text-transform: uppercase;
118	}
119	
120	/* ---------- Marquee ticker ---------- */
121	.marqueeTrack {
122	  width: 100%;
123	  overflow: hidden;
124	  border-top: 1px solid rgba(255, 255, 255, 0.06);
125	  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
126	  padding: clamp(14px, 2vh, 20px) 0;
127	  margin: clamp(40px, 6vh, 64px) 0;
128	}
129	
130	.marqueeInner {
131	  display: flex;
132	  white-space: nowrap;
133	  animation: marquee 32s linear infinite;
134	  font-size: clamp(11px, 0.9vw, 13px);
135	  font-weight: 500;
136	  letter-spacing: 0.28em;
137	  text-indent: 0.28em;
138	  color: rgba(255, 255, 255, 0.22);
139	}
140	
141	@keyframes marquee {
142	  0%   { transform: translateX(0); }
143	  100% { transform: translateX(-33.333%); }
144	}
145	
146	/* ---------- Feature card grid ---------- */
147	.grid {
148	  display: grid;
149	  grid-template-columns: repeat(2, 1fr);
150	  gap: 1px;
151	  background: rgba(255, 255, 255, 0.07);
152	  border: 1px solid rgba(255, 255, 255, 0.07);
153	  border-radius: 2px;
154	}
155	
156	.card {
157	  background: var(--ink);
158	  padding: clamp(28px, 4vw, 48px);
159	  opacity: 0;
160	  transition:
161	    background 0.4s var(--ease-out-cubic),
162	    transform 0.4s var(--ease-out-cubic),
163	    box-shadow 0.4s var(--ease-out-cubic);
164	  cursor: default;
165	}
166	
167	.card:hover {
168	  background: rgba(255, 255, 255, 0.03);
169	  transform: translateY(-4px);
170	  box-shadow: 0 16px 48px rgba(0, 0, 0, 0.4);
171	  z-index: 1;
172	  position: relative;
173	}
174	
175	.cardIndex {
176	  display: block;
177	  font-size: 11px;
178	  font-weight: 500;
179	  letter-spacing: 0.3em;
180	  color: rgba(255, 255, 255, 0.22);
181	  margin-bottom: clamp(16px, 2.5vh, 24px);
182	}
183	
184	.cardTitle {
185	  font-size: clamp(18px, 1.8vw, 26px);
186	  font-weight: 600;
187	  line-height: 1.2;
188	  letter-spacing: -0.02em;
189	  color: var(--paper);
190	  margin-bottom: clamp(14px, 2vh, 20px);
191	}
192	
193	.cardRule {
194	  width: 24px;
195	  height: 1px;
196	  background: rgba(255, 255, 255, 0.2);
197	  margin-bottom: clamp(14px, 2vh, 20px);
198	  transition: width 0.4s var(--ease-out-cubic), background 0.4s;
199	}
200	
201	.card:hover .cardRule {
202	  width: 40px;
203	  background: var(--amber);
204	}
205	
206	.cardBody {
207	  font-size: clamp(13px, 1vw, 15px);
208	  font-weight: 400;
209	  line-height: 1.72;
210	  color: rgba(255, 255, 255, 0.38);
211	}
212	
213	/* ---------- Responsive ---------- */
214	@media (max-width: 720px) {
215	  .stats {
216	    grid-template-columns: 1fr;
217	  }
218	
219	  .statItem {
220	    border-right: none;
221	    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
222	  }
223	
224	  .statItem:last-child {
225	    border-bottom: none;
226	  }
227	
228	  .grid {
229	    grid-template-columns: 1fr;
230	  }
231	}
232

1	/* ============================================================
2	   Globe Section — full-viewport, deep space, immersive
3	   Continuous dark from About, transitions to paper for Showcase
4	   ============================================================ */
5	
6	.section {
7	  position: relative;
8	  min-height: 100vh;
9	  background: radial-gradient(ellipse at 50% 30%, #0d1a2e 0%, #070d18 50%, #030608 100%);
10	  color: var(--paper);
11	  font-family: var(--font-display);
12	  overflow: hidden;
13	  display: flex;
14	  flex-direction: column;
15	  align-items: center;
16	}
17	
18	/* ── Starfield canvas ─────────────────────── */
19	.starfield {
20	  position: absolute;
21	  inset: 0;
22	  width: 100%;
23	  height: 100%;
24	  pointer-events: none;
25	  z-index: 0;
26	}
27	
28	/* ── Text block — top center ──────────────── */
29	.text {
30	  position: relative;
31	  z-index: 2;
32	  text-align: center;
33	  padding: clamp(56px, 8vh, 96px) clamp(24px, 6vw, 80px) 0;
34	  max-width: 720px;
35	}
36	
37	.eyebrow {
38	  font-size: clamp(10px, 0.8vw, 12px);
39	  font-weight: 500;
40	  letter-spacing: 0.44em;
41	  text-indent: 0.44em;
42	  color: rgba(106, 166, 255, 0.7);
43	  margin-bottom: clamp(16px, 2vh, 24px);
44	}
45	
46	.headline {
47	  font-size: clamp(44px, 7vw, 100px);
48	  font-weight: 600;
49	  line-height: 0.97;
50	  letter-spacing: -0.04em;
51	  color: var(--paper);
52	  margin-bottom: clamp(16px, 2.5vh, 24px);
53	}
54	
55	.sub {
56	  font-size: clamp(13px, 1.1vw, 16px);
57	  font-weight: 400;
58	  letter-spacing: 0.04em;
59	  color: rgba(255, 255, 255, 0.38);
60	}
61	
62	/* ── Globe ────────────────────────────────── */
63	.globeWrap {
64	  position: relative;
65	  z-index: 1;
66	  margin-top: clamp(-40px, -4vh, -20px);
67	  flex: 1;
68	  display: flex;
69	  justify-content: center;
70	  align-items: center;
71	  will-change: transform, opacity;
72	}
73	
74	.placeholder {
75	  border-radius: 50%;
76	  background: radial-gradient(
77	    circle at 38% 38%,
78	    rgba(30, 58, 138, 0.25),
79	    rgba(3, 6, 8, 0.9)
80	  );
81	}
82	
83	/* ── Bottom transition — ink → paper ─────── */
84	.bottomFade {
85	  position: relative;
86	  z-index: 3;
87	  width: 100%;
88	  height: 30vh;
89	  background: linear-gradient(to bottom, transparent 0%, var(--paper) 100%);
90	  pointer-events: none;
91	  flex-shrink: 0;
92	}
93

1	/* ============================================================
2	   Aircraft Showcase Section
3	   Layout: 3-column grid (headline-left | aircraft | model-right)
4	   followed by a spec grid and CTA
5	   ============================================================ */
6	
7	.showcase {
8	  position: relative;
9	  background: var(--paper);
10	  color: var(--ink);
11	  font-family: var(--font-display);
12	  padding: clamp(64px, 10vw, 120px) clamp(24px, 6vw, 80px);
13	  overflow: hidden;
14	}
15	
16	/* ---------- Main 3-col layout ---------- */
17	.inner {
18	  display: grid;
19	  grid-template-columns: 1fr 1.1fr 1fr;
20	  align-items: center;
21	  gap: clamp(24px, 4vw, 48px);
22	  max-width: 1440px;
23	  margin: 0 auto;
24	}
25	
26	/* ---------- Left headline ---------- */
27	.headlineLeft {
28	  opacity: 0;
29	}
30	
31	.kicker {
32	  font-size: clamp(10px, 0.8vw, 12px);
33	  font-weight: 500;
34	  letter-spacing: 0.38em;
35	  text-indent: 0.38em;
36	  color: rgba(10, 13, 18, 0.4);
37	  margin-bottom: clamp(16px, 2.5vh, 28px);
38	}
39	
40	.headlineText {
41	  font-size: clamp(36px, 5vw, 72px);
42	  font-weight: 600;
43	  line-height: 0.95;
44	  letter-spacing: -0.03em;
45	  color: var(--ink);
46	}
47	
48	/* ---------- Aircraft SVG placeholder ---------- */
49	.aircraftWrap {
50	  display: flex;
51	  justify-content: center;
52	  align-items: center;
53	  opacity: 0;
54	  padding: clamp(16px, 2vw, 32px) 0;
55	}
56	
57	.aircraftSvg {
58	  width: clamp(140px, 18vw, 260px);
59	  height: auto;
60	  color: var(--ink);
61	}
62	
63	/* ---------- Right model info ---------- */
64	.headlineRight {
65	  opacity: 0;
66	}
67	
68	.modelNumber {
69	  font-size: clamp(40px, 6vw, 88px);
70	  font-weight: 600;
71	  letter-spacing: -0.04em;
72	  line-height: 0.9;
73	  color: var(--ink);
74	  margin-bottom: clamp(12px, 1.5vh, 20px);
75	}
76	
77	.modelCategory {
78	  font-size: clamp(13px, 1.1vw, 16px);
79	  font-weight: 500;
80	  letter-spacing: 0.01em;
81	  color: var(--ink);
82	  line-height: 1.4;
83	  margin-bottom: clamp(16px, 2.5vh, 28px);
84	}
85	
86	.modelDesc {
87	  font-size: clamp(13px, 1vw, 15px);
88	  font-weight: 400;
89	  line-height: 1.65;
90	  color: rgba(10, 13, 18, 0.55);
91	  max-width: 320px;
92	}
93	
94	/* ---------- Divider ---------- */
95	.divider {
96	  max-width: 1440px;
97	  margin: clamp(40px, 6vh, 64px) auto;
98	  height: 1px;
99	  background: rgba(10, 13, 18, 0.1);
100	}
101	
102	/* ---------- Spec grid ---------- */
103	.specs {
104	  display: grid;
105	  grid-template-columns: repeat(3, 1fr);
106	  gap: clamp(24px, 4vh, 40px) clamp(24px, 4vw, 48px);
107	  max-width: 1440px;
108	  margin: 0 auto;
109	}
110	
111	.specItem {
112	  display: flex;
113	  flex-direction: column;
114	  gap: 6px;
115	  opacity: 0;
116	}
117	
118	.specLabel {
119	  font-size: clamp(9px, 0.75vw, 11px);
120	  font-weight: 500;
121	  letter-spacing: 0.3em;
122	  text-indent: 0.3em;
123	  color: rgba(10, 13, 18, 0.38);
124	  text-transform: uppercase;
